    logic [TILE_NUMBER_OF_Y_BITS-1:0] offsetY_LSB; 
    logic [MAZE_NUMBER_OF__X_BITS-1:0] offsetX_MSB;
    logic [MAZE_NUMBER_OF__Y_BITS-1:0] offsetY_MSB;

